import{_ as e,o as p,c as a,ag as r}from"./chunks/framework.DL-RKwfR.js";const m=JSON.parse('{"title":"👫 关于我们","description":"练练是得到在 2023 年 4 月启动并开始内测的一个 AI 项目。","frontmatter":{"title":"👫 关于我们","description":"练练是得到在 2023 年 4 月启动并开始内测的一个 AI 项目。","order":12,"lastUpdated":"2026-03-15T08:39:42.265Z"},"headers":[],"relativePath":"关于我们.md","filePath":"关于我们.md"}'),o={name:"关于我们.md"};function n(s,t,_,d,i,c){return p(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="👫-关于我们" tabindex="-1">👫 关于我们 <a class="header-anchor" href="#👫-关于我们" aria-label="Permalink to &quot;👫 关于我们&quot;">​</a></h1><p>大家知道，得到一直是做教育培训的，过去这些年，我们跟国内非常多的专家和老师合作出过课程，这就让我们形成了一个非常底层和基础的能力，那就是 <strong>知识萃取</strong>，把一位老师的知识、见识、视野提炼成用户喜欢的课程内容，这成了我们得到的基因。</p><p>而这离不开我们的一个部门，“总编室”积累了非常多关于企业或者个人知识萃取的经验。</p><p>我们更让他们作为 AI 训练师，和产研团队一起，训练了一个可以从知识萃取到员工个人练习的 AI 产品。</p><p>因为每个老板应该都有过一个梦，就是看到自己公司的销售冠军时，心想要是我有 100 个销冠，那是不是做梦都会笑醒？</p><p>我们初期内测客户有一家是国内超大保险公司的电销团队，就是拿他们电销团队销冠的成功订单录音，去做经验萃取。</p><p>可以看到 AI 提炼出了销售过程中比较难的场景，让每个员工都可以针对性的进行场景练习，并且给出更针对性的建议（场景和对话），最大的一个好处是没有练好的销售，就不要派出去拿珍贵的真实客户练手了。</p><p><strong>为什么我们要叫练练，而且选择以练习的方式作为解决方案？</strong></p><p>练练的 Slogan 是“重要时刻，提前练练”。</p><p>我们认为，通过观看视频 ，并不能学会骑⾃⾏⻋。</p><p>同样，你也不能通过这种⽅式，让员工学会所需的技能。</p><p>在做练练这款产品时，我们也极其强调企业经验的重要性，华为不是有一句名言吗？<strong>企业最大的浪费，就是经验的浪费。</strong></p><p>而企业经验如何萃取出来，这恰恰是得到所擅长的。</p>',13)])])}const f=e(o,[["render",n]]);export{m as __pageData,f as default};
